const now = Date.now();
const tasks = $input.all().map(i => i.json).filter(t => t && t.id);
const isDone = t => String(t.status) === 'Done';
const dueMs = t => { const d = new Date(t.due_date).getTime(); return isNaN(d) ? null : d; };
const overdue = tasks.filter(t => !isDone(t) && dueMs(t) !== null && dueMs(t) < now);
const toUpdate = overdue.filter(t => String(t.status) !== 'Overdue');
const byMember = {};
tasks.forEach(t => { const key = String(t.task_owner_email || 'unassigned'); if (!byMember[key]) { byMember[key] = []; } byMember[key].push(t); });
const metrics = Object.keys(byMember).sort().map(email => { const list = byMember[email]; const done = list.filter(isDone); const od = list.filter(t => !isDone(t) && dueMs(t) !== null && dueMs(t) < now); const durations = done.filter(t => t.completed_at && t.created_at).map(t => (new Date(t.completed_at).getTime() - new Date(t.created_at).getTime()) / 86400000).filter(d => !isNaN(d) && d >= 0); const avg = durations.length ? Math.round((durations.reduce((a, b) => a + b, 0) / durations.length) * 10) / 10 : null; return { bd_member_email: email, total_tasks: list.length, completed_tasks: done.length, completion_rate: list.length ? Math.round((done.length / list.length) * 100) / 100 : 0, overdue_count: od.length, avg_completion_time_days: avg }; });
return [{ json: { user_email: 'n8n@workflow.internal', action: 'accountability_daily_check', table_name: 'team_tasks', new_values: { checked_at: new Date().toISOString(), total_tasks: tasks.length, overdue_count: overdue.length, newly_marked_overdue: toUpdate.length, metrics: metrics }, overdue_task_ids: toUpdate.map(t => t.id) } }];
